const input = $input.first().json;
const isForm = 'tema' in input;
const tema = isForm ? input.tema : null;
const tipo = isForm ? input.tipo : 'Tutorial paso a paso';
const duracion = isForm ? input.duracion : 'Estándar (10-12 min)';
const runDate = new Date().toLocaleDateString('es-ES');
return [{ json: { tema, tipo, duracion, isForm, runDate } }];

const items = $input.first().json.items || [];
const nacho_leo_id = items[0]?.id || '';
const prev = $node['Normalizar entrada'].json;
return [{ json: { nacho_leo_id, tema: prev.tema, tipo: prev.tipo, duracion: prev.duracion, isForm: prev.isForm, runDate: prev.runDate } }];

const items = $input.first().json.items || [];
const nacho_video_ids = items.map(i => i.id?.videoId).filter(Boolean).join(',');
const prev = $node['Extraer ID Nacho Leo'].json;
return [{ json: { nacho_video_ids, tema: prev.tema, tipo: prev.tipo, duracion: prev.duracion, isForm: prev.isForm, runDate: prev.runDate, nacho_leo_id: prev.nacho_leo_id } }];

const items = $input.first().json.items || [];
const prev = $node['Extraer IDs vídeos Nacho Leo'].json;

const nacho_text = items.map((v, i) => {
  const views = parseInt(v.statistics?.viewCount || 0).toLocaleString('es');
  const likes = parseInt(v.statistics?.likeCount || 0).toLocaleString('es');
  const comments = parseInt(v.statistics?.commentCount || 0).toLocaleString('es');
  const title = v.snippet?.title || '';
  const date = (v.snippet?.publishedAt || '').substring(0, 10);
  const desc = (v.snippet?.description || '').substring(0, 120).replace(/\n/g, ' ');
  return (i+1) + '. "' + title + '"\n   Fecha: ' + date + ' | Views: ' + views + ' | Likes: ' + likes + ' | Comentarios: ' + comments + '\n   Descripción: ' + desc;
}).join('\n\n');

return [{ json: { nacho_text, tema: prev.tema, tipo: prev.tipo, duracion: prev.duracion, isForm: prev.isForm, runDate: prev.runDate } }];

const items = $input.first().json.items || [];
const my_ids = items.map(i => i.id?.videoId).filter(Boolean).join(',');
const prev = $node['Formatear contexto competidor'].json;
return [{ json: { my_ids, nacho_text: prev.nacho_text, tema: prev.tema, tipo: prev.tipo, duracion: prev.duracion, isForm: prev.isForm, runDate: prev.runDate } }];

const response = $input.first().json;
const script = response.choices?.[0]?.message?.content || 'Error: no se pudo generar el script';
const ctx = $node['Construir prompt definitivo'].json;

// Extract title from generated script
const titleMatch = script.match(/# GUIÓN:\s*"([^"]+)"/);
const extractedTitle = titleMatch ? titleMatch[1].substring(0, 60) : null;
const runDate = ctx.runDate || new Date().toLocaleDateString('es-ES');
let doc_title;
if (extractedTitle) {
  doc_title = '[SCRIPT] ' + extractedTitle + ' — ' + runDate;
} else if (ctx.tema) {
  doc_title = '[SCRIPT] ' + ctx.tema.substring(0, 50) + ' — ' + runDate;
} else {
  doc_title = '[SCRIPT AUTO] ' + runDate;
}

return [{ json: { script, doc_title } }];
